-----------------------------------------------------------------
function LFightIdleObject:Create(ctrl,objKey,objType,side,objData,objParentTrans, isNewMoveType)
	self._ctrl = ctrl
	self._manager = ctrl:GetManager()

	self._rootTrans = objParentTrans
	self._objKey = objKey
	self._objType = objType
	self._side = side
	self._objData = objData
	self._randZ = math.random(100,999) * 0.0000001

	self._isNewMoveType = isNewMoveType

	if not self:InitData() then return false end
	self:InitDisplay()
	self:InitObjectAI()
	self:InitActor()
	return true
end

--初始化数据
function LFightIdleObject:InitData()
	local objData = self._objData
	local aniShowEffRef = nil
	local objName = nil
	local attrData = {}
	local commandSkill

	local skillList = {}

	local bInitHp = false

	local careerType = 0

	local skin = nil

	local objType = self._objType

	if objType == LFightIdleConst.OBJ_MON then
		local monRef = GameTable.MonsterAttrRef[objData.refId]
		if not monRef then
			LogError("怪物不存在 refId"..tostring(objData.refId))
			return false
		end
		local effectId = monRef.effectId
		aniShowEffRef = GameTable.CharacterEffectRef[effectId]
		commandSkill = monRef.commonSkill
		objName = ccLngText(monRef.name)
		if string.isempty(objName) then
			objName = ccLngText(aniShowEffRef.name)
		end

		--self._quality = monRef.quality
		local attrRef = GameTable.MonsterAttrRef[objData.attrRefId]
		if attrRef then
			attrData = {
				[LAttrConst.Atk] = attrRef.Atk,
				[LAttrConst.Def] = attrRef.Def,
				[LAttrConst.MaxHP] = attrRef.MaxHP,
				[LAttrConst.Speed] = attrRef.Speed,
				[LAttrConst.Crit] = attrRef.Crit,
				[LAttrConst.DefCrit] = attrRef.DefCrit,
				[LAttrConst.Hit] = attrRef.Hit,
				[LAttrConst.CritRatio] = attrRef.CritRatio,
				[LAttrConst.AddHurt] = attrRef.AddHurt,
				[LAttrConst.AvoidHurt] = attrRef.AvoidHurt,
				[LAttrConst.PHurt] = attrRef.PHurt,
				[LAttrConst.PAvoidHurt] = attrRef.PAvoidHurt,
				[LAttrConst.MHurt] = attrRef.MHurt,
				[LAttrConst.MAvoidHurt] = attrRef.MAvoidHurt,
				[LAttrConst.AddHurt1] = attrRef.AddHurt1,
				[LAttrConst.AddHurt2] = attrRef.AddHurt2,
				[LAttrConst.AddHurt3] = attrRef.AddHurt3,
				[LAttrConst.AddHurt4] = attrRef.AddHurt4,
			}
		end
		careerType = monRef.careerType
		self._bHaveBlood = true
	elseif objType == LFightIdleConst.OBJ_MISSION then
		local monRef = GameTable.MonsterAttrRef[objData.monRefId]
		if not monRef then
			LogError("怪物不存在 refId"..tostring(objData.monRefId))
			return false
		end
		local effectId = monRef.effectId
		aniShowEffRef = GameTable.CharacterEffectRef[effectId]
		commandSkill = monRef.commonSkill
		objName = ccLngText(monRef.name)
		if string.isempty(objName) then
			if not aniShowEffRef then
				LogError("怪物HeroEffectRef配置不存在 refId="..tostring(effectId))
				return false
			end
			objName = ccLngText(aniShowEffRef.name)
		end
		self._bHaveHeadName = true
		-- self._isBossShow = (objData.bossShow or 0) > 0
		self._isBossShow = false
		self._patrolWaitTime = 3
	elseif objType == LFightIdleConst.OBJ_BOSS then
		local monRef = GameTable.MonsterAttrRef[objData.monRefId]
		if not monRef then
			LogError("怪物不存在 refId"..tostring(objData.monRefId))
			return false
		end
		local effectId = monRef.effectId
		aniShowEffRef = GameTable.CharacterEffectRef[effectId]
		commandSkill = monRef.commonSkill
	else
		bInitHp = true

		self._bHaveBlood = true
		if self._isNewMoveType then
			self._bHaveBlood = false
		end

		local heroRef = gModelHero:GetHeroRef(objData.refId)

		if not heroRef then
			LogError("英雄不存在 refId"..tostring(objData.refId))
			return false
		end

		local starRef = gModelHero:GetHeroStarRef(objData.refId,objData.form,objData.star)

		--更换小人
		skin = objData.skin
		local heroEffectId
		if skin and skin > 0 then
			heroEffectId = skin
		else
			heroEffectId = starRef.effectId
		end
		local starId = starRef.refId

		local heroEffRef = GameTable.CharacterEffectRef[heroEffectId]
		if objData.isUseEffect then
			heroEffRef = objData.effectRef
		end

		self._locationType = heroEffRef.posOnHook
		--self._directOnHook = heroEffRef.directOnHook

		aniShowEffRef = heroEffRef
		commandSkill = starRef.commonSkill

		objName = ccLngText(heroEffRef.name)

		careerType = heroRef.careerType

		local gradeId = gModelHero:ConvertToHeroGradeId(heroRef.classType,objData.grade)

		local atk,maxHp,def,speed = gModelHero:GetBaseAttrInfo(objData.refId,objData.lv,starId,gradeId)

		local heroInitCritRatio = GameTable.CharacterConfigRef["heroInitCritRatio"]

		attrData = {
			[LAttrConst.Atk] = atk,
			[LAttrConst.Def] = def,
			[LAttrConst.MaxHP] = maxHp,
			[LAttrConst.Speed] = speed,
			[LAttrConst.CritRatio] = heroInitCritRatio
		}

		local unLockSkillIdList = objData.id and gModelHero:GetUnLockSkillIdListByHeroId(objData.id) or {}
		skillList = self:FilterActiveHurtSkill(unLockSkillIdList,skin)
	end

	self._curHp = attrData[LAttrConst.MaxHP] or 0
	self._hpMax = self._curHp
	self._moveSpeed = attrData[LAttrConst.Speed] or 0

	self._careerType = careerType

	self._spineName = aniShowEffRef.prefabName
	self._aniShowEffectRef = aniShowEffRef

	self._objName = objName

	self._attrData = attrData

	self._bInitHp = bInitHp

	self._commonSkill = self:CreateSkillData(commandSkill, true, skin)
	self._skillList = skillList

	return true
end

--更新英雄属性数据
function LFightIdleObject:UpdateAttr(attrList)
	local attrData = {}
	for k,v in pairs(attrList) do
		attrData[k] = v
	end
	self._attrData = attrData

	local curHP = self._curHp
	local hpMax = self._hpMax

	local newMax = attrData[LAttrConst.MaxHP]
	if not newMax then
		return
	end
	local rate = 1
	if hpMax > 0 then
		rate = curHP / hpMax
	end
	self._hpMax = newMax
	self._curHp = math.floor(newMax * rate)
end

------------------------------------------------------------------
function LFightIdleObject:GetTopNodePos()
	if not self._displayObj:IsDpValid() then return nil end
	local topNode = self._topNodeTrans
	if not topNode then
		local dpTrans = self:GetDpObject():GetDisplayTrans()
		topNode = CS.FindTrans(dpTrans,"TopNode")
		self._topNodeTrans = topNode
	end
	return topNode.position
end



---解锁的主动伤害技能
function LFightIdleObject:FilterActiveHurtSkill(unLockSkillIdList, skin)
	local skillList = {}
	for k,v in ipairs(unLockSkillIdList) do
		local skilldata  = self:CreateSkillData(v, false, skin)
		if skilldata then
			table.insert(skillList,skilldata)
		end
	end
	return skillList
end

function LFightIdleObject:CreateSkillData(skillRefId, bNormal, skin)
	return LFightIdleConst.CreateSkillData(skillRefId, bNormal, skin)
end

