function LFightIdleObject:RecordRecoverRateCheck(rate)
	local dicCheck = self._lastRecoverRateCheck or {}
	dicCheck[rate] = true
	self._lastRecoverRateCheck = dicCheck
end

function LFightIdleObject:IsRecoverCheckRate(rate)
	if self._lastRecoverRateCheck then
		return self._lastRecoverRateCheck[rate]
	end
end

function LFightIdleObject:ResetRecoverLifeHp()
	local rate = 1
	if self._hpMax > 0 then
		rate = self._curHp / self._hpMax
	end
	self._lastRecoverHpRate = rate
	self._lastRecoverRateCheck = {}
end

function LFightIdleObject:GetLastRecoverHpRate()
	return self._lastRecoverHpRate
end
-----------------------------------------------------------------
function LFightIdleObject:DoHurt(changeType,changeVal)
	local hp = self._curHp
	hp = hp + changeVal
	if hp <= 0 then
		hp = 0
		self:DoDead()
	end

	local bChange = (hp ~= self._curHp)

	self._curHp = hp

	changeVal = math.abs(changeVal)

	if bChange then
		self:ChangeBloodStick(self._curHp / self._hpMax)
	end

end

