---头顶创建
function LFightIdleObject:CreateHead()
	if self._btIdleHead then return end
	if not self._displayObj:IsDpValid() then return end
	local btIdleHead = LFightIdleHead:New()
	self._btIdleHead = btIdleHead
	btIdleHead:Init(self, self._isBossShow and 1 or 0)
	btIdleHead:SetVisible(false)
	btIdleHead:StartLoad()
end

------------------------------------------------------------------
--血条创建
function LFightIdleObject:CreateBloodStick()
	if self._bloodStick then return end
	if not self._displayObj:IsDpValid() then return end
	local bloodStick = LBloodStick:New()
	local barType = self._side == LFightIdleConst.SIDE_A and 0 or 1
	local dpTarns = self._displayObj:GetDisplayTrans()
	local topNodePos = self:GetTopNodePos()
	local nowPos = dpTarns.position
	bloodStick:CreateBloodStick(barType,1,1)
	bloodStick:SetHeroTrans(dpTarns,topNodePos - nowPos)
	--我方常驻，对方不常驻
	--if self:GetSide() == LFightIdleConst.SIDE_B then
		bloodStick:SetVisible(false)
	--end
	self._bloodStick = bloodStick
	bloodStick:StartLoad()
end

function LFightIdleObject:ChangeBloodStick(rate)
	if not self._bloodStick then return end
	self._bloodStick:SetVisible(true)
	self._bloodStick:SetHpRate(rate)
end

-----------------------------------------------------------------
function LFightIdleObject:CreateBubbleStick()
	if self._bubbleStick then return end
	if not self._displayObj:IsDpValid() then return end
	local bubbleStick = LBubbleStick:New()
	local dpTarns = self._displayObj:GetDisplayTrans()
	local topNodePos = self:GetTopNodePos()
	local nowPos = dpTarns.position
	bubbleStick:CreateBubble()
	bubbleStick:SetHeroTrans(dpTarns,topNodePos - nowPos)
	self._bubbleStick = bubbleStick
end

function LFightIdleObject:ShowBubbleStick(str,time)
	local bubbleStick = self._bubbleStick
	if not bubbleStick then
		self:CreateBubbleStick()
		bubbleStick = self._bubbleStick
	end
	if not bubbleStick then return end
	bubbleStick:SetContent(str,time)
	bubbleStick:SetVisible(true)
	return true
end

-----------------------------------------------------------------
function LFightIdleObject:CreateHeadEffect()
	if self._headEffect then return end
	if string.isempty(self._headEffectName) then return end
	if not self._displayObj:IsDpValid() then return end
	if not self._topNodeTrans then return end

	local dp = LDisplayEffect:New()
	self._headEffect = dp
	dp:CreateEffect(self._topNodeTrans,self._headEffectName)
	dp:SetResTag(CS.RES_TAG_SCENE)
	dp:SetLoadedFunction(function()
		if self:IsDestroy() then return end
		if not self._headEffect or not self._headEffect:IsDpValid() then return end
		local dpTrans = self._headEffect:GetDisplayTrans()
		dpTrans.localPosition = Vector3(0,0.1,0)
	end)
	dp:StartLoadEffect()
end


