---绑定表演
function LFightIdleObject:InitActor()
	self._moveActor = LFightIdleMoveActor:New(self, self._manager)
	self._atkActor = LFightIdleAtkActor:New(self, self._manager)
	self._pathActor = LFightIdlePathActor:New(self, self._manager)
	self._aniActor = LFightIdleAniActor:New(self, self._manager)
	self._alphaActor = LFightIdleAlphaActor:New(self, self._manager)
end

function LFightIdleObject:StopActor(bForceStop)
	self._moveActor:StopMove()

	if not bForceStop and self._pathActor:IsPathing() and self._pathActor:IsJumping() then
		self._pathActor:WaitStopPathing()
	else
		self._pathActor:StopPathing()
	end

	self._atkActor:StopAtk()
end
-----------------------------------------------------------------
function LFightIdleObject:InitDisplay()
	local pool = self._ctrl:GetSpinePool()
	local dp = LDisplaySpine:New()
	self._displayObj = dp
	dp:CreateSpine(self._rootTrans,self._spineName)
	dp:SetUsePool(true)
	dp:SetPool(pool)
	if self._scaleSize then
		dp:SetScale(self._scaleSize)
	end
	dp:SetLoadedFunction(function()
		self:OnLoaded()
	end)
end

function LFightIdleObject:StartLoadDp()
	if not self._displayObj or self._displayObj:IsDpValid() then return end
	self._displayObj:StartLoad()
end

function LFightIdleObject:OnLoaded()
	self._displayObj:SetUseLookValid(true)
	self._displayObj:GetDisplayTrans().localPosition = self._localPosition
	self:InitBtObjectView()

	if self._bHaveBlood then
		self:CreateBloodStick()
	end

	if self._bHaveHeadName then
		self:CreateHead()
	end

	self:CreateHeadEffect()

	self:ShowBirth()
	--self:CreateBubbleStick()
end

-----------------------------------------------------------------
---出生
function LFightIdleObject:ShowBirth()
	self._status = LFightIdleConst.STATUS_BIRTH
	self:KillBirthTween()
	self._displayObj:SetAlpha(0)

	self:SetDirection(self._direction)



	local waitTime = math.random() * 0.5

	local tweenSeq = YXTween.TweenSequenceIns()

	local showtime = 1

	--self._displayObj:PauseAnimation()


	local alphaTween = YXTween.TweenFloat(0,1,showtime * 0.5,function (value)
		self._displayObj:SetAlpha(value)
	end):SetEase(DG.Tweening.Ease.InSine)

	tweenSeq:AppendInterval(waitTime)
	tweenSeq:AppendCallback(function ()
		--self._displayObj:ResumeAnimation()
		--self:PlayAni(self._aniShowEffectRef.comeAction)
		if self._isNewMoveType then
			self:PlayRunAni()
			return
		end
		if self._defaultAct then
			local timeScale = 1
			local loop = self._isLoop
			if self._defaultAct == "die" then
				timeScale = 100
			end
			self:PlayAni(self._defaultAct,loop,0,timeScale)
		else
			self:PlayIdleAni()
		end
	end)
	tweenSeq:Append(alphaTween)
	--tweenSeq:AppendInterval(showtime)
	--tweenSeq:Insert(waitTime,alphaTween)
	tweenSeq:OnComplete(function()
		self._birthTween = nil
		self._status = LFightIdleConst.STATUS_IDLE
		if self._ai then
			self._ai:StartAI()
		end
		if self:GetSide() == LFightIdleConst.OBJ_HERO then
			if self._bloodStick then self._bloodStick:SetVisible(true) end
		end

		if self._btIdleHead then
			self._btIdleHead:SetVisible(true)
		end

		if self:IsLeader() then
			self:StartCameraFollowObj()
		end

		if self._side == LFightIdleConst.SIDE_M then
			local monsterId = self._objData.monRefId
			local tran = self._displayObj:GetSpineTrans()
			--printErrorN("load monster end "..monsterId)
			FireEvent(EventNames.ON_GUIDE_SPINE_FINISH,monsterId,tran)
		end



 	end)

	self._birthTween = tweenSeq
	tweenSeq:PlayForward()
end

function LFightIdleObject:KillBirthTween()
	if self._birthTween then
		self._birthTween:Kill(false)
		self._birthTween = nil
	end
end

-----------------------------------------------------------------
function LFightIdleObject:KillDeadTween()
	if self._deadTween then
		self._deadTween:Kill(false)
		self._deadTween = nil
	end
end

---死亡
function LFightIdleObject:DoDead()
	if self._bDestroyed then return end
	if self._bDeadEnd then return end
	if self._status == LFightIdleConst.STATUS_DEAD then return end

	self._status = LFightIdleConst.STATUS_DEAD

	self:StopActor(true)

	local deadTime = LxResPathUtil.GetSpineAniTime(self._spineName, LSpineAniConst.die, 0)
	self:PlayAni(LSpineAniConst.die)

	self:KillBirthTween()
	self:KillDeadTween()


	local tweenSeq = YXTween.TweenSequenceIns()

	local showtime = 0.1

	local alphaFunc = function (value)
		self._displayObj:SetAlpha(value)
	end

	local alphaTween = YXTween.TweenFloat(1,0.5,showtime,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
	local alphaTween1 = YXTween.TweenFloat(0.5,1,showtime,alphaFunc):SetEase(DG.Tweening.Ease.OutSine)
	local alphaTween2 = YXTween.TweenFloat(1,0,showtime,alphaFunc):SetEase(DG.Tweening.Ease.InSine)

	tweenSeq:AppendInterval(deadTime)
	tweenSeq:Append(alphaTween)
	tweenSeq:Append(alphaTween1)
	tweenSeq:Append(alphaTween2)

	tweenSeq:InsertCallback(0.1,function ()
		if self._bloodStick then
			self._bloodStick:Destroy()
			self._bloodStick = nil
		end
	end)

	tweenSeq:OnComplete(function()
		self._deadTween = nil
		self._bDeadEnd = true
	end)
	self._deadTween = tweenSeq
	tweenSeq:PlayForward()

	self._manager:NotifyObjDead(self)
end
-----------------------------------------------------------------
---挂组件
function LFightIdleObject:InitBtObjectView()
	local dpTrans = self._displayObj:GetSpineTrans()
	local dpGo = dpTrans.gameObject
	local typeofBtObjectView = typeof(CardEHT.BtObjectView)
	local comp = dpGo:GetComponent(typeofBtObjectView)
	if(not comp) then
		comp = dpGo:AddComponent(typeofBtObjectView)
	end
	comp:SetRandZ(self._randZ)
	self._btObjectView = comp
	local collider = CS.FindTrans(dpTrans,"Collider")
	if collider then
		local bShow = true
		local objType = self:GetObjType()
		if objType == LFightIdleConst.OBJ_MON then
			--self._manager:SetPressMonObj(collider.gameObject,self)
			--self._manager:SetLongPressObj(collider.gameObject,self)
			bShow = false
		elseif objType == LFightIdleConst.OBJ_MISSION then
			self._manager:SetPressMissionObj(collider.gameObject,self)
		else
			bShow = false
		end

		local box2d = collider:GetComponent(typeof(UnityEngine.BoxCollider2D))
		if box2d then
			local scale = self._scaleSize or 1
			local size = box2d.size * scale
			local offset = box2d.offset * scale
			self._bodyBounds = Bounds(offset,size)
			self._bodyX = size.x * 0.5
		end

		if collider.gameObject.activeSelf ~= bShow then
			CS.ShowObject(collider.gameObject, bShow)
		end
	end
end

function LFightIdleObject:GetBtObjectView()
	return self._btObjectView
end
-----------------------------------------------------------------
---帧运行
function LFightIdleObject:OnRun(time)
	if self:IsDestroy() then return false end
	if self._status == LFightIdleConst.STATUS_DEAD then
		if self:IsDeadEnd() then
			return false
		end
	else
		local ai = self._ai
		ai:OnRun(time)
	end
	self._moveActor:OnRun(time)
	self._atkActor:OnRun(time)
	self._pathActor:OnRun(time)
	self._aniActor:OnRun(time)
	self._alphaActor:OnRun(time)

	if self._bubbleStick then self._bubbleStick:OnRun(time) end

	return true
end

-----------------------------------------------------------------
function LFightIdleObject:IsDeadEnd()
	return self._bDeadEnd
end

-----------------------------------------------------------------
function LFightIdleObject:IsReady()
	if not self._displayObj or not self._displayObj:IsDpValid() then return false end

	if self._status == LFightIdleConst.STATUS_DEAD then return false end
	if self._status == LFightIdleConst.STATUS_BIRTH then return false end

	return true
end

function LFightIdleObject:IsLive()
	if self:IsDestroy() then return false end
	if self._status == LFightIdleConst.STATUS_DEAD then return false end
	if not self._displayObj or not self._displayObj:IsDpValid() then return false end
	return true
end

function LFightIdleObject:IsDead()
	if self._status == LFightIdleConst.STATUS_DEAD then return true end
	return false
end

function LFightIdleObject:IsCanCollider()
	if not self:IsLive() then return false end
	if not self:IsReady() then return false end

	local dogeAction = self._ai:GetAction(LFightIdleConst.ACTION_DOGE)
	if not dogeAction then return false end
	if not dogeAction:IsDogeReady() then return false end
	if self._ai:IsCurrentAction(LFightIdleConst.ACTION_DOGE) then return false	end
	if self._pathActor:IsPathing() and self._pathActor:IsJumping() then return false end
	if self._atkActor:IsAttacking() then return false end

	return true

end

-----------------------------------------------------------------
function LFightIdleObject:ChangeDirToPos(tarPos)
	local dir = self._direction
	local pos = self:GetPosition()
	if pos.x < tarPos.x then
		dir = LFightIdleConst.DIRECTION_RIGHT
	elseif pos.x > tarPos.x then
		dir = LFightIdleConst.DIRECTION_LEFT
	end
	if dir ~= self._direction then
		self:SetDirection(dir)
	end
end

-----------------------------------------------------------------
function LFightIdleObject:SetDirection(dir)
	self._direction = dir
	self._displayObj:SetFlipX(dir ~= LFightIdleConst.DIRECTION_RIGHT)
end

function LFightIdleObject:GetDirection()
	return self._direction
end

function LFightIdleObject:SetPosition(pos)
	pos.z = pos.y * 0.01 + self._randZ
	self._localPosition = pos
	if not self._displayObj:IsDpValid() then return end
	self._displayObj:GetDisplayTrans().localPosition = pos
end

function LFightIdleObject:GetPosition()
	if not self._displayObj:IsDpValid() then return self._localPosition end
	return self._displayObj:GetDisplayTrans().localPosition
end

function LFightIdleObject:GetDisplayTrans()
	if not self._displayObj:IsDpValid() then return  end
	return self._displayObj:GetDisplayTrans()
end

function LFightIdleObject:SetRenderOrder(order)
	self._displayObj:SetRenderOrder(order)
end

function LFightIdleObject:GetDpObject()
	return self._displayObj
end

function LFightIdleObject:GetMoveActor()
	return self._moveActor
end

function LFightIdleObject:GetAtkActor()
	return self._atkActor
end
function LFightIdleObject:GetPathActor()
	return self._pathActor
end

function LFightIdleObject:GetMoveSpeed()
	return self._moveSpeed or 200
end

function LFightIdleObject:SetMoveSpeed(val)
	self._moveSpeed = val
end

function LFightIdleObject:SetStatus(status)
	if self._status == status then return end

	self._status = status
	return true
end

function LFightIdleObject:SetScaleSize(scale)
	self._scaleSize = scale
	if self._displayObj then
		self._displayObj:SetScale(scale)
	end
end

function LFightIdleObject:GetScaleSize()
	return self._scaleSize
end

function LFightIdleObject:SetAlpha(alpha)
	self._alphaActor:SetAlpha(alpha)
end

function LFightIdleObject:SetMaskShow(bMaskShow)
	self._isMaskShow = bMaskShow
	if bMaskShow then
		self:SetAlpha(1.0)
		self._displayObj:SetRenderLayer("ForeGround")
	else
		self._displayObj:SetRenderLayer("Object")
	end
end

function LFightIdleObject:GetMaskShow()
	return self._isMaskShow 
end

function LFightIdleObject:AlphaTwinkle(twinkleId,fromAlpha,toAlpha,time, count)
	self._alphaActor:PlayTwinkle(twinkleId,fromAlpha,toAlpha,time, count)
end

function LFightIdleObject:UpdateAlphaTwinkle(twinkleId,fromAlpha,toAlpha,time, count)
	self._alphaActor:UpdateAlphaTwinkle(twinkleId,fromAlpha,toAlpha,time, count)
end

function LFightIdleObject:SetHeadEffectName(effectName)
	self._headEffectName = effectName
end

function LFightIdleObject:SetAttSpeedUp(val)
	if val <= 0 then val = 1 end
	self._attSpeedUp = val
end

function LFightIdleObject:GetAttSpeedUp()
	return self._attSpeedUp
end

function LFightIdleObject:SetJumpCd(jumpCd)
	self._jumpCd = jumpCd
end

function LFightIdleObject:GetJumpCd()
	return self._jumpCd
end

function LFightIdleObject:GetBodyX()
	return self._bodyX
end

function LFightIdleObject:GetBodyBounds()
	return self._bodyBounds
end

function LFightIdleObject:StartCameraFollowObj()
	if not self._displayObj or not self._displayObj:IsDpValid() then return end
	self._manager:SetFollowCamera(self:GetDpObject():GetDisplayTrans())
end

-----------------------------------------------------------------
function LFightIdleObject:PlayRunAni(time)
	self:PlayAni(LSpineAniConst.run,true,time)
end

function LFightIdleObject:PlayIdleAni()
	self:PlayAni(LSpineAniConst.idle,true)
end

function LFightIdleObject:IsRunAni()
	return self._aniActor:IsAni(LSpineAniConst.run)
end

function LFightIdleObject:PlayHitAni()
	local hitAction,hitActionTime = self:GetHitActionData()
	self:PlayAni(hitAction,false,hitActionTime)
end

function LFightIdleObject:PlayJumpAni(bDown)
	local ani = LSpineAniConst.jump1
	if bDown then
		ani = LSpineAniConst.jump2
	end
	self:PlayAni(ani,true)
end

function LFightIdleObject:PlayAni(animationName,bLoop,time, timescale, mixTime)
	self._aniActor:PlayAni(animationName,bLoop,time, timescale,mixTime)
end
-----------------------------------------------------------------

function LFightIdleObject:GetHitActionData()
	local hitAction = LSpineAniConst.hit1
	local hitTime = LxResPathUtil.GetSpineAniTime(self._spineName, hitAction, 0.2)
	return hitAction,hitTime
end

function LFightIdleObject:IsCheckSameBoard()
	return self._objType == LFightIdleConst.OBJ_MON
end
-----------------------------------------------------------------
function LFightIdleObject:IsDestroy()
	return self._bDestroyed
end

function LFightIdleObject:DestroyActor()
	if self._aniActor then
		self._aniActor:Destroy()
	end
	if self._atkActor then
		self._atkActor:Destroy()
	end

	if self._moveActor then
		self._moveActor:Destroy()
	end

	if self._pathActor then
		self._pathActor:Destroy()
	end
	if self._alphaActor then
		self._alphaActor:Destroy()
	end
end

function LFightIdleObject:Destroy()
	self:KillBirthTween()
	self:KillDeadTween()
	self:DestroyActor()

	if self._bloodStick then
		self._bloodStick:Destroy()
		self._bloodStick = nil
	end

	if self._btIdleHead then
		self._btIdleHead:Destroy()
		self._btIdleHead = nil
	end

	if self._bubbleStick then
		self._bubbleStick:DestroyBubble()
		self._bubbleStick = nil
	end

	if self._headEffect then
		self._headEffect:Destroy()
		self._headEffect = nil
	end

	if self._ai then
		self._ai:Destroy()
		self._ai = nil
	end

	if(self._displayObj) then
		self._displayObj:Destroy()
	end
	self._displayObj = nil

	table.removeall(self)

	self._bDestroyed = true
end

return LFightIdleObject